const item = $input.item.json;
let source = "unknown", text = "", files = [], user = "unknown", chatId = null;

if (item.message) {
  source = "telegram";
  const m = item.message;
  user = m.from?.username || m.from?.first_name || "TelegramUser";
  chatId = m.chat?.id || m.from?.id;
  text = m.text || m.caption || "";
  if (m.document) files.push({type:"document", fileId:m.document.file_id, mimeType:m.document.mime_type||"", name:m.document.file_name||""});
  if (m.photo)    files.push({type:"image",    fileId:m.photo.slice(-1)[0].file_id, mimeType:"image/jpeg"});
  if (m.video)    files.push({type:"video",    fileId:m.video.file_id,  mimeType:"video/mp4"});
  if (m.audio)    files.push({type:"audio",    fileId:m.audio.file_id,  mimeType:"audio/mpeg"});
  if (m.voice)    files.push({type:"audio",    fileId:m.voice.file_id,  mimeType:"audio/ogg"});
}
else if (item.id && item.threadId) {
  source = "gmail";
  user = item.from || "EmailSender";
  text = item.text || item.snippet || item.subject || "";
  if (item.attachments)
    item.attachments.forEach(a => files.push({type:"attachment", name:a.filename||"", mimeType:a.mimeType||"", data:a.data||""}));
}
else if (item.entry || item.object === "whatsapp_business_account" || item.body?.entry) {
  source = "whatsapp";
  const raw = item.body || item;
  const msgs = ((raw.entry||[])[0]?.changes||[])[0]?.value?.messages||[];
  const m = msgs[0]||{};
  user = m.from || "WhatsAppUser";
  chatId = m.from;
  if (m.type==="text")     text = m.text?.body||"";
  if (m.type==="image")    files.push({type:"image",    mediaId:m.image?.id,    mimeType:"image/jpeg"});
  if (m.type==="document") files.push({type:"document", mediaId:m.document?.id, mimeType:m.document?.mime_type||"", name:m.document?.filename||""});
  if (m.type==="video")    files.push({type:"video",    mediaId:m.video?.id,    mimeType:"video/mp4"});
  if (m.type==="audio")    files.push({type:"audio",    mediaId:m.audio?.id,    mimeType:"audio/ogg"});
}

// Analysis mode detection: @finance @technical @simple @action @marketing @summary
let mode = "standard";
const modeRx = text.match(/@(finance|technical|simple|action|creative|marketing|legal|health|summary)\b/i);
if (modeRx) { mode = modeRx[1].toLowerCase(); text = text.replace(modeRx[0],"").trim(); }

const ytMatch = text.match(/(youtube\.com\/watch\?v=|youtu\.be\/)([\w-]+)/);
let contentType = "text";
if (ytMatch) { contentType = "youtube"; }
else if (files.length > 0) {
  const f = files[0];
  if (f.mimeType.includes("pdf")||(f.name||"").endsWith(".pdf")) contentType="pdf";
  else if (f.mimeType.includes("image"))  contentType="image";
  else if (f.mimeType.includes("video"))  contentType="video";
  else if (f.mimeType.includes("audio"))  contentType="audio";
  else contentType="document";
}

return { source, user, chatId, text:text.trim(), files, contentType,
         youtubeVideoId:ytMatch?.[2]||null, mode, timestamp:new Date().toISOString() };

const d = $input.item.json;
const SELF    = "https://inspiring-cat-production.up.railway.app";
const TG_TOK  = "8514342294:AAEey6kBHXav5ciipaSL1fZ7P8YSHy_pv64";

// ?? Send "Analysing." message to Telegram for instant feedback ????????????????
if (d.source === "telegram" && d.chatId) {
  try {
    await this.helpers.httpRequest({
      method:"POST", url:`https://api.telegram.org/bot${TG_TOK}/sendMessage`,
      headers:{"Content-Type":"application/json"},
      body:{chat_id:d.chatId, text:`? Analysing your ${d.contentType} content, please wait.`},
      timeout:8000
    });
  } catch(e) {}
}

async function shellTask(cmd, timeoutMs=240000) {
  const t = await this.helpers.httpRequest({
    method:"POST", url:SELF+"/tasks",
    headers:{"Content-Type":"application/json"},
    body:{type:"shell", payload:{command:cmd}}, timeout:20000
  });
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    await new Promise(r=>setTimeout(r,4000));
    const s = await this.helpers.httpRequest({method:"GET", url:`${SELF}/tasks/${s?.id||t.id}`, timeout:10000});
    if (s.status==="done") return (s.output||s.result||"").trim();
    if (s.status==="error") return "ERROR:"+s.error;
  }
  return "TIMEOUT";
}

// ?? Telegram file download ?????????????????????????????????????????????????????
if (d.source === "telegram" && d.files.length > 0 && d.files[0].fileId && !d.files[0].data) {
  try {
    const fi = await this.helpers.httpRequest({
      method:"GET",
      url:`https://api.telegram.org/bot${TG_TOK}/getFile?file_id=${d.files[0].fileId}`,
      timeout:10000
    });
    const fp = fi.result?.file_path;
    if (fp) {
      const cmd = `python3 -c "import urllib.request,base64; d=urllib.request.urlopen('https://api.telegram.org/file/bot${TG_TOK}/${fp}').read(); print(base64.b64encode(d).decode())"`;
      const b64 = await shellTask(cmd, 30000);
      if (b64 && !b64.startsWith("ERROR") && !b64.startsWith("TIMEOUT") && b64.length > 50) {
        d.files[0].data = b64;
        if (fp.endsWith(".pdf")) d.files[0].mimeType = "application/pdf";
        if (fp.endsWith(".png")) d.files[0].mimeType = "image/png";
      }
    }
  } catch(e) {}
}

// ?? YouTube: check PG cache (24h dedup) ????????????????????????????????????????
let cachedAnalysis = null;
if (d.contentType === "youtube" && d.youtubeVideoId) {
  try {
    const cacheCmd = `python3 -c "
import os, psycopg2
conn=psycopg2.connect(os.environ['DATABASE_URL'].replace('postgres://','postgresql://'))
cur=conn.cursor()
cur.execute('''CREATE TABLE IF NOT EXISTS content_analyst_history(
  id BIGSERIAL PRIMARY KEY,content_type TEXT,source TEXT,user_id TEXT,
  label TEXT,youtube_id TEXT,analysis TEXT,mode TEXT,created_at TIMESTAMPTZ DEFAULT NOW())''')
conn.commit()
cur.execute('''SELECT analysis FROM content_analyst_history
  WHERE youtube_id=%s AND created_at>NOW()-INTERVAL '24 hours'
  ORDER BY created_at DESC LIMIT 1''', ('${d.youtubeVideoId}',))
row=cur.fetchone()
print(row[0][:8000] if row else 'NOCACHE')
conn.close()
"`;
    const res = await shellTask(cacheCmd, 20000);
    if (res && res !== "NOCACHE" && !res.startsWith("ERROR") && !res.startsWith("TIMEOUT")) {
      cachedAnalysis = res;
    }
  } catch(e) {}
}

// ?? Content extraction ?????????????????????????????????????????????????????????
let extracted = d.text || "(no content)";
let label = "Text Message";

if (cachedAnalysis) {
  // Cache hit - skip extraction
  label = `YouTube (${d.youtubeVideoId}) ?? cached`;
}
else if (d.contentType === "youtube" && d.youtubeVideoId) {
  label = `YouTube (${d.youtubeVideoId})`;
  const vid = d.youtubeVideoId;
  const cmd = `python3 -c "
vid='${vid}'
try:
  from youtube_transcript_api import YouTubeTranscriptApi
  t=YouTubeTranscriptApi.get_transcript(vid,languages=['en','pt','es','fr','de'])
  print(' '.join([x['text'] for x in t])[:6000])
except Exception as e:
  import subprocess,json
  r=subprocess.run(['yt-dlp','--dump-json','--no-download','https://youtube.com/watch?v='+vid],capture_output=True,text=True,timeout=30)
  if r.returncode==0:
    info=json.loads(r.stdout)
    print('TITLE: '+info.get('title','')+'\\nCHANNEL: '+info.get('channel','')+'\\nDESC: '+info.get('description','')[:3000])
  else: print('Extraction failed: '+str(e))
"`;
  extracted = await shellTask(cmd, 120000);
}
else if (d.contentType === "pdf" && d.files.length > 0 && d.files[0].data) {
  label = `PDF - ${d.files[0].name||"document.pdf"}`;
  const b64 = d.files[0].data.replace(/\s/g,"");
  const cmd = `python3 -c "
import base64,io
try:
  from pypdf import PdfReader
  r=PdfReader(io.BytesIO(base64.b64decode('${b64}')))
  print('\\n'.join([p.extract_text() or '' for p in r.pages[:20]])[:6000])
except Exception as e:
  print('PDF extraction error: '+str(e))
"`;
  extracted = await shellTask(cmd, 60000);
}
else if (d.contentType === "image") {
  label = "Image";
  extracted = "__IMAGE__";
}
else if ((d.contentType==="video"||d.contentType==="audio") && d.files.length>0 && d.files[0].data) {
  const ext = d.contentType==="audio" ? ".ogg" : ".mp4";
  label = d.contentType==="audio" ? "Audio / Voice Note" : "Video File";
  const fileB64 = d.files[0].data.replace(/\s/g,"");
  const cmd = `python3 -c "
import base64,tempfile,os,subprocess
data=base64.b64decode('${fileB64}')
f=tempfile.NamedTemporaryFile(suffix='${ext}',delete=False)
f.write(data); f.close()
r=subprocess.run(['whisper',f.name,'--output_format','txt','--output_dir','/tmp','--language','auto'],
  capture_output=True,text=True,timeout=300)
tp=f.name.replace('${ext}','.txt')
if os.path.exists(tp): print(open(tp).read()[:6000]); os.unlink(tp)
else: print('Whisper unavailable. stdout:'+r.stdout[:2000])
os.unlink(f.name)
"`;
  extracted = await shellTask(cmd, 240000);
}
else {
  label = d.text ? "Text Message" : "Message";
  extracted = d.text || "(empty message)";
}

return { ...d, extracted, label, cachedAnalysis };

